final:
module binary_up_counter_4bit(
    input clk,
    input rst_n,
    output reg [3:0] count
);
  wire _tap_clk = clk & {1{1'b1}};


always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        count <= 4'b0000;
    end else begin
        count <= count + 1;
    end
end

endmodule
